//! posixlake CLI - Mount database as POSIX filesystem via NFS server
//!
//! Usage:
//!   posixlake create <DB_PATH> --schema "id:Int64,name:String"
//!   posixlake create <DB_PATH> --from-csv <CSV_FILE>
//!   posixlake create <DB_PATH> --from-parquet <PARQUET_FILE>
//!   posixlake mount <DB_PATH> <MOUNT_POINT> [--port PORT]
//!   posixlake unmount <MOUNT_POINT>
//!   posixlake status <MOUNT_POINT>

use arrow::datatypes::{DataType, Field, Schema};
use clap::{Parser, Subcommand, ValueEnum};
use posixlake::error::{Error, Result};
#[cfg(target_os = "windows")]
use posixlake::nfs::windows::{prepare_nfs_mount, MOUNT_OPTIONS};
use posixlake::nfs::NfsServer;
use posixlake::storage::s3::parse_s3_uri;
use posixlake::DatabaseOps;
use std::net::ToSocketAddrs;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::signal;

/// Build metadata for --version output
fn long_version() -> &'static str {
    static VERSION: std::sync::OnceLock<String> = std::sync::OnceLock::new();
    VERSION.get_or_init(|| {
        format!(
            "{}\ncommit: {}\ndate: {}\ntarget: {}\nprofile: {}\nrustc: {}",
            env!("CARGO_PKG_VERSION"),
            env!("POSIXLAKE_BUILD_COMMIT"),
            env!("POSIXLAKE_BUILD_DATE"),
            env!("POSIXLAKE_BUILD_TARGET"),
            env!("POSIXLAKE_BUILD_PROFILE"),
            rustc_version(),
        )
    })
}

fn rustc_version() -> String {
    std::process::Command::new("rustc")
        .arg("--version")
        .output()
        .ok()
        .and_then(|o| String::from_utf8(o.stdout).ok())
        .map(|s| s.trim().to_string())
        .unwrap_or_else(|| "unknown".to_string())
}

/// posixlake - POSIX Filesystem Database (NFS Server)
#[derive(Parser)]
#[command(name = "posixlake")]
#[command(version = env!("CARGO_PKG_VERSION"))]
#[command(long_version = long_version())]
#[command(about = "Mount posixlake as a POSIX filesystem via NFS server", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Parser)]
#[command(name = "posixlake")]
#[command(version = env!("CARGO_PKG_VERSION"))]
#[command(long_version = long_version())]
#[command(about = "Mount posixlake as a POSIX filesystem via NFS server", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Create a new Delta Lake database
    Create {
        /// Path for the new database
        #[arg(value_name = "DB_PATH")]
        db_path: PathBuf,

        /// Schema definition: "col1:Type1,col2:Type2,..."
        /// Supported types: Int64, Int32, Float64, Float32, String, Boolean
        #[arg(long, conflicts_with_all = ["from_csv", "from_parquet"])]
        schema: Option<String>,

        /// Create database by importing from CSV file (auto-infers schema)
        #[arg(long, conflicts_with_all = ["schema", "from_parquet"])]
        from_csv: Option<PathBuf>,

        /// Create database by importing from Parquet file(s) (supports glob patterns)
        #[arg(long, conflicts_with_all = ["schema", "from_csv"])]
        from_parquet: Option<PathBuf>,

        /// Enable authentication and RBAC on the new database
        #[arg(long)]
        auth: bool,

        /// Admin username for the initial admin user (requires --auth)
        #[arg(long, requires = "auth", default_value = "admin")]
        admin_user: String,

        /// Admin password for the initial admin user (requires --auth).
        /// If omitted with --auth, reads from POSIXLAKE_ADMIN_PASSWORD env var.
        #[arg(long, requires = "auth")]
        admin_password: Option<String>,
    },

    /// Mount a database as a filesystem via NFS
    Mount {
        /// Path to the database directory
        #[arg(value_name = "DB_PATH")]
        db_path: PathBuf,

        /// Mount point directory
        #[arg(value_name = "MOUNT_POINT")]
        mount_point: PathBuf,

        /// NFS server port (default: 12049)
        #[arg(long, short = 'p', default_value = "12049")]
        port: u16,

        /// Username for authentication (or set POSIXLAKE_USER env var)

/// Mount point directory
        #[arg(value_name = "MOUNT_POINT")]
        mount_point: PathBuf,

        /// NFS server port (default: 12049)
        #[arg(long, short = 'p', default_value = "12049")]
        port: u16,

        /// Username for authentication (or set POSIXLAKE_USER env var)
        #[arg(long, short = 'u')]
        user: Option<String>,

        /// Password for authentication (or set POSIXLAKE_PASSWORD env var)
        #[arg(long)]
        password: Option<String>,
    },

    /// Unmount a mounted database
    Unmount {
        /// Mount point to unmount
        #[arg(value_name = "MOUNT_POINT")]
        mount_point: PathBuf,
    },

    /// Check mount status
    Status {
        /// Mount point to check
        #[arg(value_name = "MOUNT_POINT")]
        mount_point: PathBuf,
    },

    /// Check database health
    Health {
        /// Path to the database
        #[arg(value_name = "DB_PATH")]
        db_path: PathBuf,

        /// Username for authentication (or set POSIXLAKE_USER env var)
        #[arg(long, short = 'u')]
        user: Option<String>,

        /// Password for authentication (or set POSIXLAKE_PASSWORD env var)
        #[arg(long)]
        password: Option<String>,
    },

    /// Show database metrics
    Metrics {
        /// Path to the database
        #[arg(value_name = "DB_PATH")]
        db_path: PathBuf,

        /// Username for authentication (or set POSIXLAKE_USER env var)
        #[arg(long, short = 'u')]
        user: Option<String>,

        /// Password for authentication (or set POSIXLAKE_PASSWORD env var)
        #[arg(long)]
        password: Option<String>,

#[arg(value_name = "DB_PATH")]
        db_path: PathBuf,

        /// Username for authentication (or set POSIXLAKE_USER env var)
        #[arg(long, short = 'u')]
        user: Option<String>,

        /// Password for authentication (or set POSIXLAKE_PASSWORD env var)
        #[arg(long)]
        password: Option<String>,
    },

    /// Test S3/MinIO backend
    S3Test {
        /// S3 URI (e.g., s3://bucket/path)
        #[arg(value_name = "S3_PATH")]
        s3_path: String,

        /// MinIO endpoint (default: http://localhost:9000)
        #[arg(long, default_value = "http://localhost:9000")]
        endpoint: String,

        /// Access key (default: minioadmin)
        #[arg(long, default_value = "minioadmin")]
        access_key: String,

        /// Secret key (default: minioadmin)
        #[arg(long, default_value = "minioadmin")]
        secret_key: String,
    },

    /// Manage S3/MinIO local test environment
    S3 {
        #[command(subcommand)]
        command: S3Commands,
    },
}

#[derive(Subcommand)]
enum S3Commands {
    /// Start local S3/MinIO for testing
    Start {
        /// Container engine to use
        #[arg(long, value_enum, default_value = "docker")]
        engine: S3Engine,

        /// Start mode: compose (docker-compose.yml)
        #[arg(long, value_enum, default_value = "compose")]
        mode: S3Mode,

        /// Compose file path
        #[arg(long, default_value = "docker-compose.yml")]
        compose_file: PathBuf,
    },

    /// Stop local S3/MinIO
    Stop {
        /// Container engine to use
        #[arg(long, value_enum, default_value = "docker")]
        engine: S3Engine,

/// Compose file path
        #[arg(long, default_value = "docker-compose.yml")]
        compose_file: PathBuf,
    },

    /// Stop local S3/MinIO
    Stop {
        /// Container engine to use
        #[arg(long, value_enum, default_value = "docker")]
        engine: S3Engine,

        /// Stop mode: compose (docker-compose.yml)
        #[arg(long, value_enum, default_value = "compose")]
        mode: S3Mode,

        /// Compose file path
        #[arg(long, default_value = "docker-compose.yml")]
        compose_file: PathBuf,
    },
}

#[derive(ValueEnum, Clone, Copy, Debug, PartialEq, Eq)]
enum S3Engine {
    Docker,
    Podman,
}

#[derive(ValueEnum, Clone, Copy, Debug, PartialEq, Eq)]
enum S3Mode {
    Compose,
}

