    flag.or_else(|| std::env::var("POSIXLAKE_ADMIN_PASSWORD").ok())
        .ok_or_else(|| {
            Error::InvalidOperation(
                "Admin password required: use --admin-password or set POSIXLAKE_ADMIN_PASSWORD"
                    .to_string(),
            )
        })
}

