                                value_type,
                                map_type.value_contains_null(),
                            ),
                        ]
                        .into(),
                    ),
                    false,
                );
                Ok(ArrowDataType::Map(Arc::new(entries_field), false))
            }
            other => Err(Error::Other(format!(
                "Unsupported Delta Lake type: {:?}",
                other
            ))),
        }
    }

