    ///
    /// MERGE allows INSERT, UPDATE, and DELETE operations in a single atomic transaction.
    ///
    /// # Example
    /// ```no_run
    /// use arrow::array::{Int32Array, StringArray};
    /// use arrow::datatypes::{DataType, Field, Schema};
    /// use arrow::record_batch::RecordBatch;
