    fn authorize_backup_access(
        backup_path: &Path,
        required_permission: crate::security::Permission,
        credentials: Option<(&str, &str)>,
        strict_when_auth_disabled: bool,
    ) -> Result<()> {
        let users_path = backup_path.join("_metadata").join("users.json");
        if !users_path.exists() {
            if strict_when_auth_disabled {
                return Err(Error::Other("Authentication not enabled".to_string()));
            }
            return Ok(());
        }

        let (username, password) =
            credentials.ok_or_else(|| Error::Other("Authentication required".to_string()))?;

        let user_store = crate::security::UserStore::load(&users_path)?;
        let auth_context = user_store.authenticate(username, password)?;

        let role_manager = crate::security::RoleManager::new();
        if !role_manager.has_permission(&auth_context.roles, &required_permission) {
            return Err(Error::Other(format!(
                "Permission denied: {:?}",
                required_permission
            )));
        }

        Ok(())
    }

    async fn audit_backup_operation(
        backup_path: &Path,
        username: Option<&str>,
        operation: &str,
        details: &str,
        success: bool,
    ) {
        let audit_path = backup_path.join("_metadata").join("audit.json");

}

    async fn audit_backup_operation(
        backup_path: &Path,
        username: Option<&str>,
        operation: &str,
        details: &str,
        success: bool,
    ) {
        let audit_path = backup_path.join("_metadata").join("audit.json");
        if !audit_path.exists() {
            return;
        }

        if let Ok(logger) = crate::security::AuditLogger::new(audit_path) {
            let _ = logger
                .log(
                    username.unwrap_or("anonymous").to_string(),
                    operation.to_string(),
                    details.to_string(),
                    success,
                )
                .await;
        }
    }
